require("GameUtility")require("Game.MJ.MJPai")ActionNewCard={}local a=GameUtility.ERule_Mode;local b=GameUtility.EMJ_Mode;local c=TimerMgr:Init()function ActionNewCard.Play(d)LogTool.Info("Action","ActionNewCard Play data: "..pt.block(d))DesktopMgr.Inst.field_spell=d.field_spell;UIMgr.Inst:CloseUIByClassName(UI_FightBegin.className)local e=UI_FightBegin.waitTime;c:Delay(e+0.2,function()UI_DesktopInfo.Inst:OnNewCard(d,true)end)return e+10 end;function ActionNewCard.FastPlay(d)LogTool.Info("Action","ActionNewCard FastPlay data: "..pt.block(d))DesktopMgr.Inst.field_spell=d.field_spell;UIMgr.Inst:CloseUIByClassName(UI_FightBegin.className)UI_DesktopInfo.Inst:OnNewCard(d,false)return 0 end;function ActionNewCard.Record(d)LogTool.Info("Action","ActionNewCard Record data: "..pt.block(d))DesktopMgr.Inst.field_spell=d.field_spell;UIMgr.Inst:CloseUIByClassName(UI_FightBegin.className)if DesktopMgr.Inst.mode==GameUtility.EMJ_Mode.live_broadcast then UI_DesktopInfo.Inst:OnNewCard(d,true,true)else UI_DesktopInfo.Inst:OnNewCard(d)end;return 0 end;function ActionNewCard.FastRecord(d)LogTool.Info("Action","ActionNewCard FastRecord data: "..pt.block(d))DesktopMgr.Inst.field_spell=d.field_spell;UIMgr.Inst:CloseUIByClassName(UI_FightBegin.className)UI_DesktopInfo.Inst:OnNewCard(d,false)return 0 end;function ActionNewCard.ClearTimers()c:ClearAllTimers()end;return ActionNewCard